package client

import (
	"encoding/json"
	"os"
	"path/filepath"
	"testing"
)

func TestWriteCacheUsesOwnerOnlyPermissions(t *testing.T) {
	cacheDir := filepath.Join(t.TempDir(), "cache")
	c := &Client{
		BaseURL:  "https://example.test",
		cacheDir: cacheDir,
	}

	c.writeCache("/transactions", map[string]string{"limit": "1"}, json.RawMessage(`{"transactions":[]}`))

	dirInfo, err := os.Stat(cacheDir)
	if err != nil {
		t.Fatalf("stat cache dir: %v", err)
	}
	if got := dirInfo.Mode().Perm(); got&0o077 != 0 {
		t.Fatalf("cache dir mode = %#o, want no group/other permissions", got)
	}

	cacheFile := filepath.Join(cacheDir, c.cacheKey("/transactions", map[string]string{"limit": "1"})+".json")
	fileInfo, err := os.Stat(cacheFile)
	if err != nil {
		t.Fatalf("stat cache file: %v", err)
	}
	if got := fileInfo.Mode().Perm(); got&0o077 != 0 {
		t.Fatalf("cache file mode = %#o, want no group/other permissions", got)
	}
}
